mapper.select:
SELECT h.id, h.name, h.level, h.address, h.phone, h.intro, h.image,
       h.province, h.city, h.department_count, h.doctor_count, h.follow_count, h.status
FROM t_hospital h


        INNER JOIN t_hospital_department hd ON h.id = hd.hospital_id
        WHERE hd.department_id = #{departmentId}


        INNER JOIN t_hospital_department hd ON h.id = hd.hospital_id
        INNER JOIN t_department d ON hd.department_id = d.id
        WHERE d.parent_id = #{parentDepartmentId}


ORDER BY h.follow_count DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(DISTINCT h.id) FROM t_hospital h
INNER JOIN t_hospital_department hd ON h.id = hd.hospital_id WHERE hd.department_id = #{departmentId}
INNER JOIN t_hospital_department hd ON h.id = hd.hospital_id INNER JOIN t_department d ON hd.department_id = d.id WHERE d.parent_id = #{parentDepartmentId}

SELECT department_id
FROM t_hospital_department
WHERE hospital_id = #{hospitalId}
